create table orders
(
    id              bigint unsigned auto_increment
        primary key,
    created_at      datetime(3)                     null,
    updated_at      datetime(3)                     null,
    deleted_at      datetime(3)                     null,
    record_no       varchar(64)                     null comment '记录编号(唯一)',
    user_id         bigint unsigned                 null comment '用户ID',
    order_no        varchar(64)                     null comment '订单号',
    resource_type   bigint                          null comment '资源类型(1-notebook 2-training 3-inference 4-storage)',
    resource_id     bigint unsigned                 null comment '资源ID',
    product_id      bigint unsigned                 null comment '产品ID',
    product_type    bigint                          null comment '产品类型(1-计算资源 2-存储资源)',
    image_id        bigint unsigned                 null comment '镜像ID',
    charge_type     bigint                          null comment '计费类型(1-按量 2-包日 3-包周 4-包月)',
    unit_price      decimal(20, 6)                  null comment '单价',
    quantity        bigint         default 0        null comment '数量(预付费用)',
    duration        bigint         default 0        null comment '累计时长秒数(按量计费用)',
    amount          decimal(20, 6)                  null comment '金额',
    discount_amount decimal(20, 6) default 0.000000 null comment '优惠金额',
    start_time      datetime(3)                     null comment '服务生效时间',
    end_time        datetime(3)                     null comment '服务到期时间（预付费）',
    pay_time        datetime(3)                     null comment '支付时间(预付费)',
    settle_time     datetime(3)                     null comment '结算时间(按量计费)',
    status          bigint                          null comment '状态(1-使用中 2-已停止 3-已结算 4-已到期)',
    area            varchar(50)                     null comment '区域',
    cluster_id      bigint unsigned                 null comment '集群ID',
    remark          varchar(500)                    null comment '备注',
    constraint idx_orders_record_no
        unique (record_no)
);

create index idx_order_no
    on orders (order_no);

create index idx_orders_deleted_at
    on orders (deleted_at);

create index idx_resource
    on orders (resource_type);

create index idx_resource_id
    on orders (resource_id);

create index idx_status
    on orders (status);

create index idx_time_range
    on orders (start_time);

create index idx_user_time
    on orders (user_id, start_time);

